insert into menu_items (id, restaurant_id, name, category, description, sort_order) values
  ('franks-redhot-creamy-garlic-chicken-mcmuffin', 'mcdonalds-canada', 'Frank''s RedHot Creamy Garlic Chicken McMuffin', 'Breakfast', 'Our signature Chicken McMuffin breakfast sandwich with a creamy garlic kick. A breaded seasoned chicken patty, made with chicken raised on Canadian farms, with a creamy garlic sauce with the taste of Frank''s RedHot, and a slice of tasty processed cheese, nestled comfortably in a toasty English muffin.', 1),
  ('franks-redhot-creamy-garlic-egg-mcmuffin', 'mcdonalds-canada', 'Frank''s RedHot Creamy Garlic Egg McMuffin', 'Breakfast', 'Our signature Egg McMuffin breakfast sandwich with a creamy garlic kick. Wake your tastebuds with a freshly cracked Canada Grade A egg topped with Canadian bacon, a slice of tasty processed cheese, and a creamy garlic sauce with the taste of Frank''s RedHot, all sitting on a toasted English muffin.', 2),
  ('franks-redhot-creamy-garlic-sausage-n-egg-mcmuffin', 'mcdonalds-canada', 'Frank''s RedHot Creamy Garlic Sausage ''N Egg McMuffin', 'Breakfast', 'Our signature Sausage ''N Egg McMuffin breakfast sandwich with a creamy garlic kick. Wake your tastebuds with the savoury taste of sausage, tasty processed cheese and a freshly cracked Canada Grade A egg, topped with a creamy garlic sauce with the taste of Frank''s RedHot, all sitting on a toasty English muffin.', 3),
  ('franks-redhot-creamy-garlic-bacon-n-egg-mcmuffin', 'mcdonalds-canada', 'Frank''s RedHot Creamy Garlic Bacon ''N Egg McMuffin', 'Breakfast', 'Our signature Bacon ''N Egg McMuffin breakfast sandwich with a creamy garlic kick. Crispy hickory-smoked bacon on a freshly cracked Canada Grade A egg, topped with processed cheese and a creamy garlic sauce with the taste of Frank''s RedHot, nestled comfortably in a toasty English muffin.', 4),
  ('mighty-mcgriddle', 'mcdonalds-canada', 'Mighty McGriddles', 'Breakfast', 'Get a double portion of hickory-smoked bacon, plus a freshly-cracked Canada Grade A egg, processed cheese and savoury sausage all on two sweet, warm, maple-flavoured griddle cakes. A mighty eat to rid you of your mighty hunger.  Available until 11 AM.', 5),
  ('mighty-mcmuffin', 'mcdonalds-canada', 'Mighty McMuffin', 'Breakfast', 'Get a double portion of hickory-smoked bacon, plus a freshly-cracked Canada Grade A egg , processed cheese and savoury sausage  on a toasted English muffin. A mighty eat to rid you of your mighty hunger.', 6),
  ('spicy-egg-hash-brown-breakfast-wrap', 'mcdonalds-canada', 'Spicy Egg & Hash Brown Breakfast Wrap', 'Breakfast', 'Made with a freshly-cracked Canadian Free Run Egg and processed cheese, topped with Spicy Habanero sauce, shredded lettuce, tomato and a crispy hash brown, all wrapped in a soft white flour tortilla.', 7),
  ('chicken-hash-brown-breakfast-wrap', 'mcdonalds-canada', 'Chicken Breakfast Wrap', 'Breakfast', 'Made with a breaded seasoned chicken patty and processed cheese, topped with mayo-style sauce, shredded lettuce and a crispy hash brown, all wrapped in a soft white flour tortilla.', 8),
  ('sausage-bacon-egg-breakfast-wrap', 'mcdonalds-canada', 'Sausage, Bacon & Egg Breakfast Wrap', 'Breakfast', 'Made with savoury sausage, hickory-smoked bacon, a freshly-cracked Candian Free-Run Egg,  and processed cheese, topped with mayo-style sauce and a crispy hash brown, all  wrapped in a soft white flour tortilla.', 9),
  ('egg-n-cheese-mcmuffin', 'mcdonalds-canada', 'Egg ''N Cheese McMuffin', 'Breakfast', 'Made with a freshly cracked Canada Grade A egg and tasty processed cheese on a perfectly toasted English muffin.', 10),
  ('egg-n-cheese-mcgriddles', 'mcdonalds-canada', 'Egg ''N Cheese McGriddles', 'Breakfast', 'Made with a freshly cracked Canada Grade A egg and processed cheese on two sweet, warm, maple-flavoured griddle cakes.', 11),
  ('egg-blt-mcmuffin', 'mcdonalds-canada', 'Egg BLT McMuffin', 'Breakfast', 'This breakfast sandwich is made with a freshly cracked Canada Grade A egg, topped with crispy hickory smoked bacon (B), crisp lettuce (L) and fresh tomato (T), mayo-style sauce and a slice of processed cheese, served on a toasted English muffin.', 12),
  ('egg-blt-mcmuffin-with-shredded-lettuce', 'mcdonalds-canada', 'Egg BLT McMuffin with Shredded Lettuce (McDonald''s in Walmart)', 'Breakfast', 'This breakfast sandwich is made with a freshly cracked Canada Grade A egg, topped with crispy hickory smoked bacon (B), shredded lettuce (L) and fresh tomato (T), mayo-style sauce and a slice of processed cheese, served on a toasted English muffin. Only offered at McDonald''s in Walmart.', 13),
  ('chicken-mcmuffin', 'mcdonalds-canada', 'Chicken McMuffin', 'Breakfast', 'A breaded seasoned chicken patty, made with chicken raised on Canadian farms, with mayo- style sauce, a slice of tasty processed cheese sitting on a toasted English muffin.', 14),
  ('egg-mcmuffin', 'mcdonalds-canada', 'Egg McMuffin', 'Breakfast', 'Our signature breakfast sandwich boasts a freshly cracked Canada Grade A egg topped with Canadian bacon and a slice of tasty processed cheese, sitting happily on a toasted English muffin.', 15),
  ('sausage-n-egg-mcmuffin', 'mcdonalds-canada', 'Sausage ''N Egg McMuffin', 'Breakfast', 'The savoury taste of sausage, tasty processed cheese and a freshly cracked Canada Grade A egg add up to triple deliciousness on a toasty English muffin.', 16),
  ('bacon-n-egg-mcmuffin', 'mcdonalds-canada', 'Bacon ''N Egg McMuffin', 'Breakfast', 'Take your bacon and eggs the tasty way. Crispy hickory smoked bacon on a freshly cracked Canada Grade A egg. Topped with processed cheese, nestled comfortably in a toasty English muffin. Yum.', 17),
  ('sausage-mcmuffin', 'mcdonalds-canada', 'Sausage McMuffin', 'Breakfast', 'Wake up to delicious flavour with a big bite into savoury sausage and a slice of golden processed cheese held inside a toasted English muffin.', 18),
  ('plain-bagel-with-butter', 'mcdonalds-canada', 'Plain Bagel With Butter', 'Breakfast', 'Fall in love with one of our toasted plain bagels. Crispy on the outside, warm and chewy on the inside. Enjoy one toasted with butter today.', 19),
  ('everything-bagel-with-butter', 'mcdonalds-canada', 'Everything Bagel with Butter', 'Breakfast', 'Made with onion, garlic and sunflower seeds, topped with sesame seeds, poppy seeds and roasted onion. Enjoy one toasted with butter today. Not available in Quebec.', 20),
  ('sesame-seed-bagel-with-butter-qc-only', 'mcdonalds-canada', 'Sesame Bagel with Butter', 'Breakfast', 'A toasted bagel topped with sesame seeds, crispy on the outside, warm and tender on the inside. Enjoy one toasted with butter today.', 21),
  ('plain-bagel-with-plain-cream-cheese', 'mcdonalds-canada', 'Plain Bagel With Regular Cream Cheese Product', 'Breakfast', 'Fall in love with one of our plain bagels. Crispy on the outside, warm and chewy on the inside. Enjoy one toasted with regular cream cheese product today.', 22),
  ('everything-bagel-with-plain-cream-cheese', 'mcdonalds-canada', 'Everything Bagel With Regular Cream Cheese Product', 'Breakfast', 'Made with onion, garlic and sunflower seeds, topped with sesame seeds, poppy seeds and roasted onion. Enjoy one toasted with regular cream cheese product today. Not available in Quebec.', 23),
  ('sesame-seed-bagel-95g-with-plain-cream-cheese', 'mcdonalds-canada', 'Sesame Bagel With Regular Cream Cheese Product', 'Breakfast', 'A toasted bagel topped with sesame seeds, crispy on the outside, warm and tender on the inside. Enjoy one toasted with regular cream cheese product today.', 24),
  ('egg-blt-with-plain-bagel', 'mcdonalds-canada', 'Egg BLT Bagel with Plain Bagel', 'Breakfast', 'Made with a plain bagel, and topped with a freshly cracked Canada Grade A egg, hickory smoked bacon, sliced tomato and crisp lettuce.', 25),
  ('egg-blt-with-everything-bagel', 'mcdonalds-canada', 'Egg BLT Bagel with Everything Bagel', 'Breakfast', 'Made with an everything bagel, and topped with a freshly cracked Canada Grade A egg, hickory smoked bacon, sliced tomato and crisp lettuce. Not available in Quebec.', 26),
  ('egg-blt-with-sesame-seed-bagel', 'mcdonalds-canada', 'Sesame Egg BLT Bagel', 'Breakfast', 'Made with a sesame bagel, and topped with a freshly cracked Canada Grade A egg, hickory smoked bacon, sliced tomato and crisp lettuce.', 27),
  ('bacon-n-egg-with-plain-bagel', 'mcdonalds-canada', 'Bacon ''N Egg Bagel with Plain Bagel', 'Breakfast', 'Enjoy a plain bagel, topped with hickory smoked bacon, a freshly cracked Canada Grade A egg and slice of processed cheese.', 28),
  ('bacon-n-egg-with-everything-bagel', 'mcdonalds-canada', 'Bacon ''N Egg Bagel with Everything Bagel', 'Breakfast', 'Enjoy an everything bagel, topped with hickory smoked bacon, a freshly cracked Canada Grade A egg and slice of processed cheese. Not available in Quebec.', 29),
  ('bacon-n-egg-with-sesame-seed-bagel', 'mcdonalds-canada', 'Sesame Bacon ''N Egg Bagel', 'Breakfast', 'Enjoy a sesame bagel, topped with hickory smoked bacon, a freshly cracked Canada Grade A egg and slice of processed cheese.', 30),
  ('sausage-n-egg-with-plain-bagel', 'mcdonalds-canada', 'Sausage ''N Egg Bagel with Plain Bagel', 'Breakfast', 'Delicious sausage and a freshly cracked Canada Grade A egg with processed cheese, all in between a plain bagel.', 31),
  ('sausage-n-egg-with-everything-bagel', 'mcdonalds-canada', 'Sausage ''N Egg Bagel with Everything Bagel', 'Breakfast', 'Delicious sausage and a freshly cracked Canada Grade A egg with processed cheese, all in between an everything bagel. Not available in Quebec.', 32),
  ('sausage-n-egg-with-sesame-seed-bagel', 'mcdonalds-canada', 'Sesame Sausage ''N Egg Bagel', 'Breakfast', 'Delicious sausage and a freshly cracked Canada Grade A egg with processed cheese, all in between a sesame bagel.', 33),
  ('chicken-mcgriddles', 'mcdonalds-canada', 'Chicken McGriddles', 'Breakfast', 'A breaded seasoned chicken patty, made with chicken raised on Canadian farms, on two sweet, warm maple-flavoured griddle cakes.', 34),
  ('bacon-egg-cheese-mcgriddles', 'mcdonalds-canada', 'Bacon, Egg & Cheese McGriddles', 'Breakfast', 'Sizzling crispy hickory smoked bacon, a freshly cracked Canada Grade A egg and processed cheese piled up on two sweet, warm, maple-flavoured griddle cakes.', 35),
  ('sausage-egg-cheese-mcgriddles', 'mcdonalds-canada', 'Sausage Egg & Cheese McGriddles', 'Breakfast', 'Savoury sausage, a freshly cracked Canada Grade A egg and processed cheese piled up on two sweet, warm, maple-flavoured griddle cakes.', 36),
  ('sausage-mcgriddles', 'mcdonalds-canada', 'Sausage McGriddles', 'Breakfast', 'Savoury sausage piled up on two sweet, warm, maple-flavoured griddle cakes.', 37),
  ('breakfast-burrito', 'mcdonalds-canada', 'Breakfast Burrito', 'Breakfast', 'A savoury mix of fluffy eggs, tomatoes, green chilies, onions, sausage and processed cheese all wrapped in a warm white flour tortilla and served with salsa on the side.', 38),
  ('english-muffin-with-butter', 'mcdonalds-canada', 'English Muffin with Butter', 'Breakfast', 'Melted butter sitting happily on a toasted English muffin.', 39),
  ('hash-browns', 'mcdonalds-canada', 'Hash Browns', 'Breakfast', 'That crisp, flaky, fluffy-on-the-inside favourite. A perfect breakfast companion, and irresistible on its own.', 40),
  ('hotcakes-with-syrup-and-butter', 'mcdonalds-canada', 'Hotcakes with Syrup and Butter', 'Breakfast', 'Three golden-brown, melt-in-your-mouth hotcakes served with butter and tasty syrup on the side.', 41),
  ('hotcakes', 'mcdonalds-canada', 'Hotcakes', 'Breakfast', 'Start the day with three golden-brown, melt-in-your-mouth hotcakes.', 42),
  ('hockey-hero-burger', 'mcdonalds-canada', 'Hockey Hero Burger', 'Beef', 'The Hockey Hero Burger is back on the ice after a long break, with a fresh take. Made with three juicy 100% Canadian beef patties, shredded lettuce, crispy hickory-smoked bacon, processed cheese and mayo-style sauce on a toasted homestyle bun - one bite and you''ll know why it''s called the Hockey Hero Burger.', 43),
  ('cheeseburger-deluxe', 'mcdonalds-canada', 'Cheeseburger Deluxe', 'Beef', 'Your favourite cheeseburger is now made deluxe! A slice of processed cheese on a juicy, 100% Canadian beef patty with pickles and onions, ketchup, mustard, mayo style sauce, tomato, and shredded lettuce on a toasted bun.', 44),
  ('double-hamburger', 'mcdonalds-canada', 'Double Hamburger', 'Beef', 'Made with two juicy 100% Canadian beef patties, topped with pickles, onions, ketchup and mustard on a freshly toasted bun.', 45),
  ('big-mac-sandwich', 'mcdonalds-canada', 'Big Mac', 'Beef', 'Nothing compares to two 100% Canadian beef patties, special sauce, crisp lettuce, processed cheese, pickles and onions on a toasted sesame seed bun.', 46),
  ('double-big-mac-200946', 'mcdonalds-canada', 'The Big Mac-David - Double Big Mac', 'Beef', 'Four 100% Canadian beef patties, special sauce, crisp lettuce, processed cheese, pickles, and onions, all stacked on a toasted sesame seed bun. A bold burger that leads the way, just like #97 on the ice.', 47),
  ('hamburger', 'mcdonalds-canada', 'Hamburger', 'Beef', 'The comforting taste of the juicy and delicious 100% Canadian beef burger, topped with tangy pickles, ketchup, mustard and the sweet bite of onion, all on a freshly toasted bun. Just like you remember.', 48),
  ('mcdouble', 'mcdonalds-canada', 'McDouble', 'Beef', 'A slice of melted processed cheese between two 100% Canadian beef patties, topped with pickles, onions, ketchup and mustard on a toasted bun.', 49),
  ('cheeseburger', 'mcdonalds-canada', 'Cheeseburger', 'Beef', 'A slice of melted processed cheese on a juicy, 100% Canadian beef patty with tangy pickles and onions, ketchup and mustard on a freshly-toasted bun.', 50),
  ('double-cheeseburger', 'mcdonalds-canada', 'Double Cheeseburger', 'Beef', 'We make it like we always have: two slices of processed cheese with two 100% Canadian beef patties, pickles, onions, ketchup and mustard on a freshly toasted bun.', 51),
  ('quarter-pounder-with-cheese', 'mcdonalds-canada', 'Quarter Pounder with Cheese', 'Beef', 'A quarter pound* of 100% Canadian beef and two slices of melty processed cheese on a toasted sesame seed bun. Order today!
